webpackJsonp([0xf927f8900006],{743:function(e,t){e.exports={data:{page:{id:"/home/travis/build/simonagren/simonagren.github.io/content/pages/1--about/index.md absPath of file >>> MarkdownRemark",html:'<h3>Who am I?</h3>\n<p>My name is Simon Ågren. I’m a father of two awesome boys, and we live with our family in Umeå, Sweden.\nI work as a consultant at <a href="http://www.sogeti.com">Sogeti</a> with primarily SharePoint, Office365 and Azure. Over the past few years I’ve worked a lot on the clienside with React, TypeScript, NodeJS, Angular etc…</p>\n<h3>What is it about?</h3>\n<p>The blogging on this site is to share my own learnings as I go. I expect that will strengthen my understanding of subjects I will write about. I also hope that you find it helpful.</p>\n<p>It will be both simple findings and maybe some more elaborate tutorials/instructions.</p>',frontmatter:{title:"Hi there"}},site:{siteMetadata:{facebook:{appId:"2263145610597628"}}}},pathContext:{slug:"/about/"}}}});
